const raw = ($json && typeof $json === 'object') ? $json : {};
const errors = [];

// ---- deterministic string hash (djb2) -------------------------------------
function hashStr(s) {
  let h = 5381;
  for (let i = 0; i < s.length; i++) { h = ((h * 33) ^ s.charCodeAt(i)) >>> 0; }
  return ('00000000' + h.toString(16)).slice(-8);
}
function trimOrEmpty(v) { return (v === null || v === undefined) ? '' : String(v).trim(); }

// ---- required fields ------------------------------------------------------
const title = trimOrEmpty(raw.title);
const objective = trimOrEmpty(raw.objective);
const expected_deliverable = trimOrEmpty(raw.expected_deliverable);
if (!title) errors.push('Missing required field: title.');
if (!objective) errors.push('Missing required field: objective.');
if (!expected_deliverable) errors.push('Missing required field: expected_deliverable.');

// ---- enums with defaults --------------------------------------------------
const allowedPriority = ['low', 'normal', 'high', 'critical'];
let priority = trimOrEmpty(raw.priority).toLowerCase();
if (!priority) { priority = 'normal'; }
else if (allowedPriority.indexOf(priority) === -1) { errors.push('Invalid priority: ' + priority + '.'); priority = 'normal'; }

const allowedSource = ['owner', 'github_issue', 'manual', 'scheduled'];
let source = trimOrEmpty(raw.source).toLowerCase();
if (!source) { source = 'owner'; }
else if (allowedSource.indexOf(source) === -1) { errors.push('Invalid source: ' + source + '.'); source = 'owner'; }

let requested_by = trimOrEmpty(raw.requested_by);
if (!requested_by) { requested_by = 'owner'; }

// ---- budget ---------------------------------------------------------------
let maximum_budget_usd = raw.maximum_budget_usd;
if (maximum_budget_usd === null || maximum_budget_usd === undefined || maximum_budget_usd === '') {
  maximum_budget_usd = 0.75;
} else {
  maximum_budget_usd = Number(maximum_budget_usd);
}
if (typeof maximum_budget_usd !== 'number' || isNaN(maximum_budget_usd)) {
  errors.push('maximum_budget_usd is not a number.');
  maximum_budget_usd = 0.75;
} else if (maximum_budget_usd < 0.01) {
  errors.push('maximum_budget_usd below minimum (0.01).');
} else if (maximum_budget_usd > 5) {
  errors.push('maximum_budget_usd above maximum (5).');
}

// ---- optional / nullable fields ------------------------------------------
const business_reason = (raw.business_reason === null || raw.business_reason === undefined || trimOrEmpty(raw.business_reason) === '') ? null : trimOrEmpty(raw.business_reason);

let related_github_issue = null;
if (raw.related_github_issue !== null && raw.related_github_issue !== undefined && raw.related_github_issue !== '') {
  const n = Number(raw.related_github_issue);
  if (isNaN(n)) { errors.push('related_github_issue is not a number.'); } else { related_github_issue = n; }
}

let deadline = null;
if (raw.deadline !== null && raw.deadline !== undefined && trimOrEmpty(raw.deadline) !== '') {
  const d = new Date(raw.deadline);
  if (isNaN(d.getTime())) { errors.push('deadline is not a valid ISO date.'); } else { deadline = d.toISOString(); }
}

const allowed_write_scope = Array.isArray(raw.allowed_write_scope) ? raw.allowed_write_scope : [];

// Mandatory forbidden actions — always enforced, always present, deduped.
const MANDATORY_FORBIDDEN = ['architecture_change', 'code_write', 'branch_create', 'pull_request_create', 'merge', 'production_deploy', 'auth_change', 'rls_change', 'sql_execute', 'migration_create_or_apply', 'secret_access_or_change', 'production_private_data_access', 'docs_index_edit', 'knowledge_debt_close', 'beta_ready_claim', 'release_ready_claim'];
const providedForbidden = Array.isArray(raw.forbidden_actions) ? raw.forbidden_actions.map(function (x) { return String(x); }) : [];
const forbidden_actions = [];
for (const f of MANDATORY_FORBIDDEN) { if (forbidden_actions.indexOf(f) === -1) forbidden_actions.push(f); }
for (const f of providedForbidden) { if (f && forbidden_actions.indexOf(f) === -1) forbidden_actions.push(f); }

const metadata = (raw.metadata && typeof raw.metadata === 'object' && !Array.isArray(raw.metadata)) ? raw.metadata : {};

// ---- generated fields -----------------------------------------------------
const received_at = new Date().toISOString();
const canonical = [
  title, objective, expected_deliverable, business_reason || '', priority,
  String(maximum_budget_usd), requested_by, source, deadline || '',
  related_github_issue === null ? '' : String(related_github_issue)
].join('|');
const mission_hash = hashStr(canonical);

let mission_id = trimOrEmpty(raw.mission_id);
if (!mission_id) { mission_id = 'MISSION-' + mission_hash + '-' + hashStr(received_at); }

// ---- budget governance ----------------------------------------------------
const reserved_budget_usd = Math.round(maximum_budget_usd * 0.25 * 10000) / 10000;
const available_budget_usd = Math.round(maximum_budget_usd * 0.75 * 10000) / 10000;
const role_stop_threshold_pct = 75;
const role_stop_threshold_usd = Math.round(maximum_budget_usd * 0.75 * 10000) / 10000;

// ---- execution limits (deterministic caps) --------------------------------
const limits = { max_retries: 1, max_fallbacks: 1, max_critic_cycles: 1 };

const mission = {
  mission_id: mission_id,
  title: title,
  objective: objective,
  business_reason: business_reason,
  expected_deliverable: expected_deliverable,
  priority: priority,
  related_github_issue: related_github_issue,
  maximum_budget_usd: maximum_budget_usd,
  allowed_write_scope: allowed_write_scope,
  forbidden_actions: forbidden_actions,
  deadline: deadline,
  requested_by: requested_by,
  source: source,
  metadata: metadata
};

const missionValid = errors.length === 0;

return {
  json: {
    mission: mission,
    mission_id: mission_id,
    mission_hash: mission_hash,
    received_at: received_at,
    mode: 'report-only',
    missionValid: missionValid,
    errors: errors,
    errorsText: errors.join(' | '),
    budget: {
      maximum_budget_usd: maximum_budget_usd,
      reserved_budget_usd: reserved_budget_usd,
      available_budget_usd: available_budget_usd,
      role_stop_threshold_pct: role_stop_threshold_pct,
      role_stop_threshold_usd: role_stop_threshold_usd
    },
    limits: limits
  }
};

const j = $json || {};
const missionHash = (j.mission_hash || '').toString();
const missionId = (j.mission_id || '').toString();

const RETENTION_MS = 7 * 24 * 60 * 60 * 1000; // 7 days
const MAX_RECORDS = 100;
const nowMs = Date.now();

// Workflow-level static data survives across executions (Phase 1 store).
const staticData = $getWorkflowStaticData('global');
let records = Array.isArray(staticData.staff00MissionHashes) ? staticData.staff00MissionHashes : [];

// Purge expired records (older than retention window).
records = records.filter(function (r) { return r && typeof r.ts === 'number' && (nowMs - r.ts) < RETENTION_MS; });

let duplicate = false;
let original_mission_id = '';
for (const r of records) {
  if (r.hash === missionHash) {
    duplicate = true;
    original_mission_id = (r.mission_id || '').toString();
    break;
  }
}

if (!duplicate && missionHash) {
  records.push({ hash: missionHash, mission_id: missionId, ts: nowMs });
  // Cap total records; keep the most recent MAX_RECORDS.
  if (records.length > MAX_RECORDS) { records = records.slice(records.length - MAX_RECORDS); }
}

staticData.staff00MissionHashes = records;

const out = Object.assign({}, j, {
  duplicate: duplicate,
  original_mission_id: duplicate ? original_mission_id : missionId
});
return { json: out };

const j = $json || {};
const m = (j.mission && typeof j.mission === 'object') ? j.mission : {};
const budget = (j.budget && typeof j.budget === 'object') ? j.budget : {};

// Canonical supported roles (always the full universe for skipped_roles).
const ALL_ROLES = ['Project Coordinator', 'Archivist', 'Product Lead', 'Tech Lead', 'QA Lead', 'UX Lead', 'Security Lead', 'Supabase Steward', 'Release Manager', 'Market Analyst', 'GitHub Operator', 'Replit Operator', 'Sprint Planner', 'Critic'];

const title = (m.title || '').toString().toLowerCase();
const objective = (m.objective || '').toString().toLowerCase();
const deliverable = (m.expected_deliverable || '').toString().toLowerCase();
const hay = (title + ' ' + objective + ' ' + deliverable);
function has(words) { for (const w of words) { if (hay.indexOf(w) !== -1) return true; } return false; }

// Deterministic category detection (first match wins, ordered by risk/priority).
let category = 'documentation alignment';
let activated = ['Project Coordinator', 'Archivist', 'Product Lead'];

if (has(['auth', 'rls', 'row level security', 'supabase', 'data privacy', 'private data', 'security', 'secret'])) {
  category = 'auth/RLS/data';
  activated = ['Project Coordinator', 'Security Lead', 'Supabase Steward', 'Tech Lead', 'QA Lead'];
} else if (has(['bug', 'defect', 'crash', 'error', 'investigat', 'regression', 'broken', 'fix'])) {
  category = 'bug investigation';
  activated = ['Project Coordinator', 'QA Lead', 'Tech Lead'];
} else if (has(['architecture', 'refactor', 'system design', 'scalab', 'design review', 'tech debt', 'technical debt'])) {
  category = 'architecture review';
  activated = ['Project Coordinator', 'Tech Lead', 'Product Lead', 'Archivist'];
} else if (has(['market', 'competitor', 'research', 'analysis', 'pricing', 'segment', 'audience'])) {
  category = 'market research';
  activated = ['Project Coordinator', 'Market Analyst', 'Product Lead', 'Archivist'];
} else if (has(['qa', 'test', 'beta', 'quality', 'acceptance', 'verify'])) {
  category = 'beta QA';
  activated = ['Project Coordinator', 'QA Lead', 'Product Lead'];
} else if (has(['doc', 'documentation', 'readme', 'guide', 'checklist', 'align'])) {
  category = 'documentation alignment';
  activated = ['Project Coordinator', 'Archivist', 'Product Lead'];
}

// Dedup + preserve canonical order for activated roles.
const activatedSet = {};
for (const r of activated) { activatedSet[r] = true; }
const activated_roles = ALL_ROLES.filter(function (r) { return !!activatedSet[r]; });
const skipped_roles = ALL_ROLES.filter(function (r) { return !activatedSet[r]; });
const routing_reason = 'Deterministic keyword routing matched category "' + category + '" -> ' + activated_roles.join(', ') + '. No AI used.';

// ---- per-role budget split (report-only, deterministic) --------------------
const available = (typeof budget.available_budget_usd === 'number') ? budget.available_budget_usd : 0;
const n = activated_roles.length || 1;
const per_role_cost = Math.floor((available / n) * 10000) / 10000;

const forbidden_actions = Array.isArray(m.forbidden_actions) ? m.forbidden_actions : [];
const allowed_actions = ['read', 'analyze', 'summarize', 'draft_report', 'recommend']; // report-only defaults

function roleTask(role) {
  return role + ' contribution for mission: ' + (m.title || '');
}
function roleGoal(role) {
  return 'Provide a report-only ' + role + ' assessment supporting: ' + (m.objective || '');
}

const context_packs = activated_roles.map(function (role) {
  return {
    mission_id: (j.mission_id || m.mission_id || '').toString(),
    role: role,
    task: roleTask(role),
    goal: roleGoal(role),
    allowed_actions: allowed_actions,
    forbidden_actions: forbidden_actions,
    expected_output: (m.expected_deliverable || 'Report-only assessment.'),
    token_budget: 2000,
    call_limit: 2,
    cost_limit_usd: per_role_cost,
    retry_limit: 1,
    data_classification: 'internal-nonsensitive'
  };
});

return {
  json: Object.assign({}, j, {
    routing_category: category,
    activated_roles: activated_roles,
    skipped_roles: skipped_roles,
    routing_reason: routing_reason,
    context_packs: context_packs
  })
};

const items = $input.all();
const out = [];
for (const it of items) {
  const j = it.json || {};
  const packs = Array.isArray(j.context_packs) ? j.context_packs : [];
  const shared = {
    mission_id: (j.mission_id || '').toString(),
    budget: (j.budget && typeof j.budget === 'object') ? j.budget : {},
    guardrails: (j.mission && Array.isArray(j.mission.forbidden_actions)) ? j.mission.forbidden_actions : [],
    activated_roles: Array.isArray(j.activated_roles) ? j.activated_roles : [],
    skipped_roles: Array.isArray(j.skipped_roles) ? j.skipped_roles : [],
    routing_category: (j.routing_category || '').toString(),
    routing_reason: (j.routing_reason || '').toString()
  };
  for (const p of packs) {
    out.push({ json: Object.assign({}, shared, { context_pack: p, role: (p && p.role) || '' }) });
  }
}
// If no packs were produced, emit nothing (nothing to execute).
return out;

const j = $json || {};
const cp = (j.context_pack && typeof j.context_pack === 'object') ? j.context_pack : {};
const role = (cp.role || j.role || '').toString();
const mission_id = (j.mission_id || cp.mission_id || '').toString();

return {
  json: {
    mission_id: mission_id,
    role: role,
    status: 'completed',
    summary: 'Synthetic structural-test result for role ' + role + '. No AI was used.',
    verified_facts: [],
    findings: [],
    risks: [],
    conflicts: [],
    recommendation: 'No recommendation (synthetic structural test).',
    evidence: [],
    proposed_changes: [],
    checks: [],
    blockers: [],
    token_usage: 0,
    estimated_cost_usd: 0,
    synthetic: true,
    report_only: true,
    // carried forward for aggregation / governance (not part of the result schema)
    _shared: {
      budget: (j.budget && typeof j.budget === 'object') ? j.budget : {},
      guardrails: Array.isArray(j.guardrails) ? j.guardrails : [],
      activated_roles: Array.isArray(j.activated_roles) ? j.activated_roles : [],
      skipped_roles: Array.isArray(j.skipped_roles) ? j.skipped_roles : []
    }
  }
};

const j = $json || {};
const errors = [];

const mission_id = (j.mission_id || '').toString();
const role = (j.role || '').toString();
const status = (j.status || '').toString();
const allowedStatus = ['completed', 'blocked', 'invalid'];

if (!mission_id) errors.push('missing_mission_id');
if (!role) errors.push('missing_role');
if (allowedStatus.indexOf(status) === -1) errors.push('unsupported_status');

const recommendation = (j.recommendation || '').toString().trim();
const recLower = recommendation.toLowerCase();
const verified_facts = Array.isArray(j.verified_facts) ? j.verified_facts : [];
const findings = Array.isArray(j.findings) ? j.findings : [];
const evidence = Array.isArray(j.evidence) ? j.evidence : [];
const isFactual = recommendation.length > 0 && recLower.indexOf('no recommendation') === -1 && (verified_facts.length > 0 || findings.length > 0);
if (isFactual && evidence.length === 0) errors.push('missing_evidence_for_factual_recommendation');

const cost = Number(j.estimated_cost_usd);
if (isNaN(cost) || cost < 0) errors.push('negative_or_invalid_cost');

// Forbidden action found in proposed_changes.
const guardrails = (j._shared && Array.isArray(j._shared.guardrails)) ? j._shared.guardrails : [];
const proposed = Array.isArray(j.proposed_changes) ? j.proposed_changes : [];
const proposedText = JSON.stringify(proposed).toLowerCase();
let forbiddenHit = false;
for (const f of guardrails) { if (f && proposedText.indexOf(String(f).toLowerCase()) !== -1) { forbiddenHit = true; break; } }
const HARD = ['commit', 'branch', 'pull request', 'merge', 'deploy', 'migration', 'drop table', 'alter table', 'delete from', 'rls', 'row level security', 'auth_change', 'sql_execute'];
if (!forbiddenHit) { for (const h of HARD) { if (proposedText.indexOf(h) !== -1) { forbiddenHit = true; break; } } }
if (forbiddenHit) errors.push('forbidden_action_in_proposed_changes');

// Secrets / private-data fields anywhere in the result.
const scan = JSON.stringify({ s: j.summary, r: recommendation, e: evidence, f: findings, p: proposed, b: j.blockers }).toLowerCase();
const SECRET = ['password', 'api_key', 'api-key', 'apikey', 'secret', 'token', '-----begin', 'ghp_', 'bearer ', '.env', 'akia'];
let secretHit = false;
for (const s of SECRET) { if (scan.indexOf(s) !== -1) { secretHit = true; break; } }
if (secretHit) errors.push('secret_or_private_data_present');

const valid = errors.length === 0;

return {
  json: Object.assign({}, j, {
    validation_valid: valid,
    validation_status: valid ? status : 'invalid',
    validation_errors: errors
  })
};

const items = $input.all();
let mission_id = '';
let activated_roles = [];
let skipped_roles = [];
let budget = {};
const valid_results = [];
const invalid_results = [];
let total_token_usage = 0;
let total_estimated_cost_usd = 0;

for (const it of items) {
  const j = it.json || {};
  if (!mission_id) mission_id = (j.mission_id || '').toString();
  if (j._shared) {
    if (activated_roles.length === 0 && Array.isArray(j._shared.activated_roles)) activated_roles = j._shared.activated_roles;
    if (skipped_roles.length === 0 && Array.isArray(j._shared.skipped_roles)) skipped_roles = j._shared.skipped_roles;
    if (Object.keys(budget).length === 0 && j._shared.budget) budget = j._shared.budget;
  }
  total_token_usage += Number(j.token_usage) || 0;
  total_estimated_cost_usd += Number(j.estimated_cost_usd) || 0;

  const compact = {
    mission_id: j.mission_id,
    role: j.role,
    status: j.validation_status || j.status,
    summary: j.summary,
    recommendation: j.recommendation,
    verified_facts: j.verified_facts || [],
    findings: j.findings || [],
    risks: j.risks || [],
    conflicts: j.conflicts || [],
    evidence: j.evidence || [],
    proposed_changes: j.proposed_changes || [],
    checks: j.checks || [],
    blockers: j.blockers || [],
    token_usage: j.token_usage || 0,
    estimated_cost_usd: j.estimated_cost_usd || 0,
    synthetic: j.synthetic === true,
    report_only: j.report_only === true,
    validation_errors: j.validation_errors || []
  };
  if (j.validation_valid) valid_results.push(compact); else invalid_results.push(compact);
}

total_estimated_cost_usd = Math.round(total_estimated_cost_usd * 10000) / 10000;

return [{
  json: {
    mission_id: mission_id,
    activated_roles: activated_roles,
    skipped_roles: skipped_roles,
    budget: budget,
    valid_results: valid_results,
    invalid_results: invalid_results,
    total_token_usage: total_token_usage,
    total_estimated_cost_usd: total_estimated_cost_usd,
    synthetic: true,
    report_only: true
  }
}];

const j = $json || {};
const budget = (j.budget && typeof j.budget === 'object') ? j.budget : {};
const dispatch_budget_usd = (typeof budget.available_budget_usd === 'number') ? budget.available_budget_usd : 0;
const reserved_budget_usd = (typeof budget.reserved_budget_usd === 'number') ? budget.reserved_budget_usd : 0;
const total = Number(j.total_estimated_cost_usd) || 0;
const budget_exceeded = total > dispatch_budget_usd;

return {
  json: Object.assign({}, j, {
    dispatch_budget_usd: dispatch_budget_usd,
    reserved_budget_usd: reserved_budget_usd,
    budget_exceeded: budget_exceeded,
    budget_status: budget_exceeded ? 'blocked' : 'ok',
    auto_retry: false
  })
};

const j = $json || {};
const valid = Array.isArray(j.valid_results) ? j.valid_results : [];
const invalid = Array.isArray(j.invalid_results) ? j.invalid_results : [];
const reasons = [];

// (a) one or more invalid results
if (invalid.length > 0) reasons.push('one_or_more_invalid_results');

// (b) high-risk recommendation lacking evidence
for (const r of valid) {
  const hasRisk = Array.isArray(r.risks) && r.risks.length > 0;
  const rec = (r.recommendation || '').toString().trim().toLowerCase();
  const hasRec = rec.length > 0 && rec.indexOf('no recommendation') === -1;
  const hasEvidence = Array.isArray(r.evidence) && r.evidence.length > 0;
  if (hasRisk && hasRec && !hasEvidence) { reasons.push('high_risk_recommendation_without_evidence'); break; }
}

// (c) two roles giving materially conflicting recommendations (opposite polarity)
const NEG = ['do not', 'avoid', 'reject', 'block', 'stop', 'remove', 'delay', 'postpone', 'must not', 'should not'];
function neg(s) { for (const w of NEG) { if (s.indexOf(w) !== -1) return true; } return false; }
const recs = valid
  .map(function (r) { return (r.recommendation || '').toString().trim().toLowerCase(); })
  .filter(function (s) { return s.length > 0 && s.indexOf('no recommendation') === -1; });
let conflict = false;
for (let a = 0; a < recs.length && !conflict; a++) {
  for (let b = a + 1; b < recs.length; b++) {
    if (neg(recs[a]) !== neg(recs[b])) { conflict = true; break; }
  }
}
if (conflict) reasons.push('materially_conflicting_recommendations');

const critic_required = reasons.length > 0;

// Human-approval flag: any sensitive action proposed by any role.
const SENSITIVE = ['code', 'branch', 'commit', 'pull request', ' pr', 'merge', 'architecture', 'auth', 'rls', 'sql', 'migration', 'secret', 'production data', 'production', 'deploy', 'docs_index', 'knowledge debt', 'knowledge_debt', 'beta-ready', 'beta ready', 'beta_ready', 'release-ready', 'release ready', 'release_ready'];
let human_approval_required = false;
const allResults = valid.concat(invalid);
for (const r of allResults) {
  const pc = JSON.stringify(r.proposed_changes || []).toLowerCase();
  for (const s of SENSITIVE) { if (pc.indexOf(s) !== -1) { human_approval_required = true; break; } }
  if (human_approval_required) break;
}

return {
  json: Object.assign({}, j, {
    critic_required: critic_required,
    critic_reasons: reasons,
    max_critic_cycles: 1,
    human_approval_required: human_approval_required
  })
};

const j = $json || {};
let final_status = 'completed';
const invalid_results = Array.isArray(j.invalid_results) ? j.invalid_results : [];
if (j.budget_exceeded) final_status = 'blocked';
else if (invalid_results.length > 0) final_status = 'blocked';
else if (j.human_approval_required) final_status = 'needs_human_approval';

return {
  json: {
    staff01_result: {
      mission_id: (j.mission_id || '').toString(),
      status: final_status,
      activated_roles: j.activated_roles || [],
      skipped_roles: j.skipped_roles || [],
      valid_results: j.valid_results || [],
      invalid_results: j.invalid_results || [],
      critic_required: j.critic_required === true,
      critic_reasons: j.critic_reasons || [],
      max_critic_cycles: 1,
      human_approval_required: j.human_approval_required === true,
      budget: {
        dispatch_budget_usd: j.dispatch_budget_usd || 0,
        reserved_budget_usd: j.reserved_budget_usd || 0,
        total_estimated_cost_usd: j.total_estimated_cost_usd || 0,
        budget_exceeded: j.budget_exceeded === true
      },
      total_token_usage: j.total_token_usage || 0,
      total_estimated_cost_usd: j.total_estimated_cost_usd || 0,
      synthetic: true,
      report_only: true,
      note: 'Structural test output only. No AI model connected. No external system was written.'
    }
  }
};

const j = $json || {};

const mission_id = (j.mission_id || (j.mission && j.mission.mission_id) || '').toString();
const errorsText = (j.errorsText || (Array.isArray(j.errors) ? j.errors.join(' | ') : '')).toString();

// Whitelisted, non-sensitive input summary only. Never echo raw content or secrets.
const m = (j.mission && typeof j.mission === 'object') ? j.mission : {};
function clip(v, n) { const s = (v === null || v === undefined) ? '' : String(v); return s.length > n ? s.slice(0, n) + '...' : s; }
const sanitized_input_summary = {
  title: clip(m.title, 120),
  priority: (m.priority || '').toString(),
  source: (m.source || '').toString(),
  requested_by: (m.requested_by || '').toString(),
  maximum_budget_usd: (typeof m.maximum_budget_usd === 'number') ? m.maximum_budget_usd : null,
  has_deadline: !!m.deadline,
  related_github_issue: (m.related_github_issue === null || m.related_github_issue === undefined) ? null : Number(m.related_github_issue)
};

const failed_node = (j.failed_node || 'STAFF-00 Mission Validation').toString();
const retry_allowed = (j.retry_allowed !== undefined) ? !!j.retry_allowed : false;

return {
  json: {
    staff00_error: {
      mission_id: mission_id,
      failed_node: failed_node,
      execution_id: ($execution && $execution.id) ? $execution.id : '',
      error_message: clip(errorsText || 'Mission rejected by deterministic validation.', 500),
      retry_allowed: retry_allowed,
      sanitized_input_summary: sanitized_input_summary
    }
  }
